// Pseudo token validation sketch
async function verifyToken(token, publicKey) {
  try {
    const payload = jwt.verify(token, publicKey, {
      algorithms: ['RS256', 'ES256'],
      issuer: 'https://idp.example.com',
      audience: 'data-science-platform'
    });

    // Check token age
    const now = Math.floor(Date.now() / 1000);
    if (payload.exp - now > 900) { // Max 15 min
      throw new Error('Token lifetime exceeded policy');
    }

    // Verify device attestation claim
    if (!payload.device_trusted) {
      throw new Error('Device not attested');
    }

    return payload;
  } catch (err) {
    throw new AuthenticationError(err.message);
  }
}
```

